def create_synthetic_dataset():
    from datasets import Dataset
    import yaml

    print(f"[synthetic] Generating {len(_HINDI_PARAGRAPHS)} Hindi documents ...")

    # Repeat paragraphs to get ~500 docs (enough for many 512-token sequences)
    docs = []
    target_docs = 500
    for i in range(target_docs):
        para = _HINDI_PARAGRAPHS[i % len(_HINDI_PARAGRAPHS)]
        # Vary slightly by prepending paragraph index info in Hindi
        docs.append({"text": para})

    DATA_RAW_DIR.mkdir(parents=True, exist_ok=True)
    CONFIGS_DIR.mkdir(parents=True, exist_ok=True)

    save_path = DATA_RAW_DIR / DATASET_NAME
    sentinel  = DATA_RAW_DIR / f".{DATASET_NAME}_complete"

    if sentinel.exists():
        print(f"[synthetic] Sentinel found — dataset already exists at {save_path}")
        return save_path

    print(f"[synthetic] Saving {len(docs)} documents to {save_path} ...")
    ds = Dataset.from_list(docs)
    ds.save_to_disk(str(save_path))

    sentinel.write_text("ok")
    print(f"[synthetic] Sentinel written: {sentinel}")

    # Write a fake data_plan.yaml
    total_bytes = sum(len(d["text"].encode("utf-8")) for d in docs)
    plan = {
        "source": "SYNTHETIC (offline test)",
        "config": "verified",
        "language": "hin",
        "row_count": len(docs),
        "byte_count": total_bytes,
        "byte_count_human": f"{total_bytes/1e6:.2f} MB",
        "download_timestamp": datetime.datetime.utcnow().isoformat() + "Z",
        "note": "Synthetic dataset — bypasses HF download for pipeline smoke test",
    }
    plan_path = CONFIGS_DIR / "data_plan.yaml"
    with open(plan_path, "w", encoding="utf-8") as f:
        yaml.dump(plan, f, default_flow_style=False, allow_unicode=True)

    print(f"[synthetic] {len(docs)} docs  |  {total_bytes/1e3:.1f} KB  |  data_plan.yaml written")
    print(f"[synthetic] Dataset ready at: {save_path}")
    return save_path


if __name__ == "__main__":
    import datetime
    path = create_synthetic_dataset()
    print(f"\nDone. Run the pipeline with:\n  python run_test_pipeline.py")
